{
  "family": "Pinner Reaction",
  "candidate": {
    "substrate_smiles": [
      "CC#N",
      "CCO"
    ],
    "product_smiles": [
      "CC(=[NH2+])OCC.[Cl-]"
    ],
    "optional_reagent_smiles": [
      "Cl"
    ],
    "rationale": "This reaction shows the formation of an imino ether hydrochloride salt (a Pinner salt) from a simple aliphatic nitrile (acetonitrile) and a simple alcohol (ethanol) in the presence of dry hydrogen chloride. This is the quintessential first step of the Pinner reaction, as described in textbooks. The product, ethyl acetimidate hydrochloride, is a stable, isolable intermediate characteristic of this transformation.",
    "collision_avoidance_note": "The use of simple, acyclic, saturated aliphatic substrates (acetonitrile, ethanol) avoids overlap with reactions involving aromatic rings (e.g., Gattermann, Hoesch), complex functional groups, or ring systems. The specific formation of the imino ether salt from a nitrile and an alcohol is highly characteristic of the Pinner reaction and distinct from other nitrile transformations."
  }
}
